#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        char A[100005], B[100005];
        scanf("%s",A);
        scanf("%s",B);
        int lenA=strlen(A), lenB=strlen(B);
        if(lenA!=lenB){
            printf("NO\n");
            continue;
        }
        int cnt[26]={0};
        for(int i=0;i<lenA;i++) cnt[A[i]-'a']++;
        for(int i=0;i<lenB;i++) cnt[B[i]-'a']--;
        int ok=1;
        for(int i=0;i<26;i++) if(cnt[i]!=0){ ok=0; break; }
        printf(ok?"YES\n":"NO\n");
    }
    return 0;
}

