    while(T--){
        string A,B; cin>>A>>B;
        if(A.size()!=B.size()){
            cout<<"NO\n";
            continue;
        }
        int cnt[26]={0};
        for(char c:A) cnt[c-'a']++;
        for(char c:B) cnt[c-'a']--;
        bool ok=true;
        for(int i=0;i<26;i++) if(cnt[i]!=0){ ok=false; break; }
        cout<<(ok?"YES":"NO")<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        StringBuilder out=new StringBuilder();
        for(int t=0;t<T;t++){
            String A=br.readLine();
            String B=br.readLine();
            if(A.length()!=B.length()){
                out.append("NO\n");
                continue;
            }
            int[] cnt=new int[26];
            for(int i=0;i<A.length();i++) cnt[A.charAt(i)-'a']++;
            for(int i=0;i<B.length();i++) cnt[B.charAt(i)-'a']--;
            boolean ok=true;
            for(int v:cnt) if(v!=0){ ok=false; break; }
            out.append(ok?"YES":"NO").append('\n');
        }
        System.out.print(out.toString());
    }
}

